function persistSettingsFromInputs(){
  state.settings.company = $("settingCompany").value.trim() || "Empresa";
  state.settings.initialScore = Number($("settingInitialScore").value || 10);
  state.settings.recurrencePenalty = Number($("settingRecurrence").value || 0);
  state.settings.managers = $("settingManagers").value;
  state.categories.forEach(category => {
    const name = document.querySelector(`[data-cat-name="${category.id}"]`);
    const active = document.querySelector(`[data-cat-active="${category.id}"]`);
    if(name) category.name = name.value;
    if(active) category.active = active.value === "true";
    category.criteria.forEach(criteria => {
      const cn = document.querySelector(`[data-crit-name="${criteria.id}"]`);
      const cd = document.querySelector(`[data-crit-desc="${criteria.id}"]`);
      const ca = document.querySelector(`[data-crit-active="${criteria.id}"]`);
      if(cn) criteria.name = cn.value;
      if(cd) criteria.description = cd.value;
      if(ca) criteria.active = ca.value === "true";
    });
  });
  saveState();
  updateAutoPointFields();
  renderChecklist();
  renderDashboard();
}

