function drawRoundImage(ctx, img, x, y, size){
  ctx.save();
  ctx.beginPath();
  ctx.arc(x + size/2, y + size/2, size/2, 0, Math.PI * 2);
  ctx.clip();
  ctx.drawImage(img, x, y, size, size);
  ctx.restore();
}

function roundRect(ctx,x,y,w,h,r){
  const radius = Math.min(r,w/2,h/2);
  ctx.beginPath();
  ctx.moveTo(x+radius,y);
  ctx.arcTo(x+w,y,x+w,y+h,radius);
  ctx.arcTo(x+w,y+h,x,y+h,radius);
  ctx.arcTo(x,y+h,x,y,radius);
  ctx.arcTo(x,y,x+w,y,radius);
  ctx.closePath();
}

function drawRoundedImage(ctx,img,x,y,w,h,r){
  ctx.save();
  roundRect(ctx,x,y,w,h,r);
  ctx.clip();
  ctx.drawImage(img,x,y,w,h);
  ctx.restore();
}

function drawContainImage(ctx,img,x,y,w,h){
  if(!img) return;
  const ratio = Math.min(w / img.width, h / img.height);
  const nw = img.width * ratio;
  const nh = img.height * ratio;
  ctx.drawImage(img, x + (w - nw) / 2, y + (h - nh) / 2, nw, nh);
}

function canvasText(value){
  return String(value ?? "")
    .replaceAll("✓", "OK")
    .replaceAll("★", "*")
    .replaceAll("☆", "-")
    .replaceAll("Á", "A").replaceAll("É", "E").replaceAll("Í", "I").replaceAll("Ó", "O").replaceAll("Ú", "U")
    .replaceAll("á", "a").replaceAll("é", "e").replaceAll("í", "i").replaceAll("ó", "o").replaceAll("ú", "u")
    .replaceAll("â", "a").replaceAll("ê", "e").replaceAll("ô", "o")
    .replaceAll("ã", "a").replaceAll("õ", "o")
    .replaceAll("ç", "c").replaceAll("Ç", "C")
    .replaceAll("Ã", "A")
    .replaceAll("�", "");
}

function drawWrappedText(ctx,text,x,y,maxWidth,lineHeight,maxLines){
  const words = canvasText(text).split(/\s+/).filter(Boolean);
  let line = "";
  let lines = 0;
  for(const word of words){
    const test = line ? `${line} ${word}` : word;
    if(ctx.measureText(test).width > maxWidth && line){
      ctx.fillText(line,x,y);
      y += lineHeight;
      lines++;
      line = word;
      if(maxLines && lines >= maxLines - 1) break;
    }else{
      line = test;
    }
  }
  if(line && (!maxLines || lines < maxLines)){
    if(maxLines && words.length && lines === maxLines - 1){
      while(ctx.measureText(`${line}...`).width > maxWidth && line.length > 4) line = line.slice(0,-4);
      line = `${line}...`;
    }
    ctx.fillText(line,x,y);
  }
}

function loadImage(src){
  return new Promise(resolve => {
    const img = new Image();
    img.onload = () => resolve(img);
    img.onerror = () => resolve(null);
    img.src = src || defaultPhoto;
  });
}

