  ctx.fillStyle = "#d8dee8"; ctx.font = `600 ${sx(12)}px Arial`; drawWrappedText(ctx,`Data: ${dateText(evaluation.date)} | Periodo: ${evaluation.month || "-"}`, width - sx(274), sx(102), sx(220), sx(14), 1);

  ctx.shadowColor = "rgba(15,23,42,.12)"; ctx.shadowBlur = sx(16); ctx.shadowOffsetY = sx(6);
