async function downloadArt(scale){
  const evaluation = selectedEvaluation();
  if(!evaluation) return alert("Selecione uma avaliação para baixar.");
  await drawShareArt(evaluation, scale === 8 ? 7680 : 3840, scale === 8 ? 4320 : 2160);
  const canvas = $("shareCanvas");
  const fileName = `performance-${evaluation?.employeeSnapshot?.name || "avaliação"}-${scale}k.png`.replace(/\s+/g,"-").toLowerCase();
  let blob = null;
  try{
    blob = await new Promise(resolve => canvas.toBlob(resolve, "image/png", 1));
  }catch(error){
    console.error(error);
  }
  if(!blob){
    alert("Nao foi possivel gerar a imagem. Abra a plataforma pelo link http://127.0.0.1:8765/index.html ou gere a previa novamente. Se alguma foto tiver vindo de caminho externo, envie a foto pelo cadastro do colaborador.");
    await drawShareArt(evaluation, 1280, 720);
    return;
  }
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = fileName;
  document.body.appendChild(link);
  link.click();
  link.remove();
  setTimeout(() => URL.revokeObjectURL(url), 1000);
  await drawShareArt(evaluation, 1280, 720);
}

function sendEvaluationWhatsApp(){
  const evaluation = selectedEvaluation();
  if(!evaluation) return alert("Selecione uma avaliação para enviar.");
  const typed = prompt("Informe o WhatsApp do colaborador com DDD. O codigo do Brasil (55) sera aplicado automaticamente.", "");
  if(!typed) return;
  const digits = typed.replace(/\D/g, "");
  if(digits.length < 10) return alert("Informe DDD e numero. Exemplo: 85999999999.");
  const number = digits.startsWith("55") ? digits : `55${digits}`;
  const message = [
    `Ola ${evaluation.employeeSnapshot.name}.`,
    `Segue sua avaliação de desempenho.`,
    `Nota final: ${scoreText(evaluation.score)} - ${executiveClassification(evaluation.score).label}.`,
    performanceFeedback(evaluation.score, `${evaluation.employeeId}|${evaluation.employeeSnapshot.name}|${evaluation.date}`, occurrenceList(evaluation).length),
    location.href
  ].join("\n");
  window.open(`https://wa.me/${number}?text=${encodeURIComponent(message)}`,"_blank");
}

function exportBackup(){
  const blob = new Blob([JSON.stringify(state,null,2)],{type:"application/json"});
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.href = url;
  link.download = `performance-individual-backup-${todayISO()}.json`;
  link.click();
  URL.revokeObjectURL(url);
}

function importBackup(file){
  const reader = new FileReader();
  reader.onload = () => {
    try{
      const data = JSON.parse(reader.result);
      if(!data.employees || !data.categories) throw new Error();
      state = data;
      saveState();
      renderAll();
      alert("Backup importado.");
    }catch{
      alert("Arquivo invalido.");
    }
  };
  reader.readAsText(file);
}

function renderAll(){
  saveState();
  renderEmployees();
  renderChecklist();
  renderSettings();
  renderDashboard();
  renderTimeline();
  renderReportSelectors();
}

function setupEvents(){
  document.addEventListener("click", event => {
    const viewButton = event.target.closest("[data-view]");
    if(viewButton) setView(viewButton.dataset.view);
    const category = event.target.closest("[data-toggle-category]");
    if(category){
      const target = document.querySelector(`[data-category="${category.dataset.toggleCategory}"]`);
      const willOpen = !target?.classList.contains("is-open");
      document.querySelectorAll(".category.is-open").forEach(item => { if(item !== target) item.classList.remove("is-open"); });
      target?.classList.toggle("is-open", willOpen);
    }
    const info = event.target.closest("[data-info]");
    if(info){
      const categoryElement = info.closest(".category");
      const panel = categoryElement?.querySelector(`[data-info-panel="${info.dataset.info}"]`);
      const opening = panel?.hidden;
      categoryElement?.querySelectorAll("[data-info-panel]").forEach(item => item.hidden = true);
      categoryElement?.querySelectorAll("[data-info]").forEach(button => button.setAttribute("aria-expanded","false"));
      if(panel && opening){
        panel.hidden = false;
        info.setAttribute("aria-expanded","true");
      }
      return;
    }
    const edit = event.target.closest("[data-edit-employee]");
    if(edit){
      const employee = employeeById(edit.dataset.editEmployee);
      if(employee){
        $("employeeId").value = employee.id;$("employeeName").value = employee.name;$("employeeRole").value = employee.role;$("employeeSector").value = employee.sector;$("employeeActive").value = String(employee.active);$("employeePhotoPreview").src = employee.photo || defaultPhoto;setView("employees");
      }
    }
    const toggle = event.target.closest("[data-toggle-employee]");
    if(toggle){ const e = employeeById(toggle.dataset.toggleEmployee); if(e){e.active = !e.active; saveState(); renderAll();} }
    const del = event.target.closest("[data-delete-employee]");
    if(del && confirm("Excluir colaborador e manter histórico ja salvo?")){ state.employees = state.employees.filter(e => e.id !== del.dataset.deleteEmployee); saveState(); renderAll(); }
    const note = event.target.closest("[data-note]");
    if(note){
      editingNoteKey = note.dataset.note;
      if(!currentEval.occurrences[editingNoteKey]) setOccurrence(editingNoteKey, true);
      $("noteText").value = currentEval.occurrences[editingNoteKey].note || "";
      $("occurrenceQuantity").value = currentEval.occurrences[editingNoteKey].quantity || "";
      $("occurrenceSeverity").value = quantitySeverity(currentEval.occurrences[editingNoteKey].quantity).label;
      $("occurrenceStatus").value = currentEval.occurrences[editingNoteKey].status || "pending";
      const action = currentEval.occurrences[editingNoteKey].correctiveAction || "";
      const knownActions = [...$("correctiveAction").options].map(option => option.value || option.textContent);
      $("correctiveAction").value = knownActions.includes(action) ? action : (action ? "Outro" : "");
      $("correctiveOther").value = knownActions.includes(action) ? "" : action;
      $("correctiveOtherWrap").hidden = $("correctiveAction").value !== "Outro";
      $("evidencePhoto").value = $("evidenceVideo").value = $("evidenceAudio").value = "";
      $("noteDialogTitle").textContent = currentEval.occurrences[editingNoteKey].criteriaName;
      $("noteDialog").showModal();
    }
    const report = event.target.closest("[data-report-id]");
    if(report){ setView("reports"); $("reportEvaluation").value = report.dataset.reportId; renderSelectedReport(); }
    const viewEmployeeHistory = event.target.closest("[data-view-employee-history]");
    if(viewEmployeeHistory){ $("historyEmployee").value = viewEmployeeHistory.dataset.viewEmployeeHistory; renderTimeline(); }
    const resolve = event.target.closest("[data-resolve-opportunity]");
    if(resolve) resolveOpportunity(resolve.dataset.resolveOpportunity);
    const contest = event.target.closest("[data-contest]");
    if(contest) contestOccurrence(contest.dataset.contest);
    const addCriteria = event.target.closest("[data-add-criteria]");
    if(addCriteria){ state.categories.find(c => c.id === addCriteria.dataset.addCriteria)?.criteria.push({id:uid("crit"),name:"Novo criterio",description:"Descreva a ocorrencia",points:0,active:true}); saveState(); renderAll(); }
    const addCat = event.target.closest("#addCategoryButton");
    if(addCat){ state.categories.push({id:uid("cat"),name:"Nova categoria",description:"",active:true,criteria:[]}); saveState(); renderAll(); }
    const delCat = event.target.closest("[data-delete-category]");
    if(delCat && confirm("Excluir categoria?")){ state.categories = state.categories.filter(c => c.id !== delCat.dataset.deleteCategory); saveState(); renderAll(); }
    const delCrit = event.target.closest("[data-delete-criteria]");
    if(delCrit && confirm("Excluir criterio?")){ const [catId, critId] = delCrit.dataset.deleteCriteria.split("|"); const cat = state.categories.find(c => c.id === catId); if(cat) cat.criteria = cat.criteria.filter(c => c.id !== critId); saveState(); renderAll(); }
  });
  document.addEventListener("change", event => {
    if(event.target.matches("[data-check]")){ setOccurrence(event.target.dataset.check, event.target.checked); if(event.target.checked) event.target.closest(".criterion-row").querySelector("[data-note]")?.focus(); }
    if(event.target.id === "evalEmployee"){ currentEval.employeeId = event.target.value; renderSelectedEmployee(); }
    if(event.target.id === "historyEmployee") renderTimeline();
    if(event.target.id === "dashboardSector") renderDashboard();
    if(event.target.id === "reportEvaluation") renderSelectedReport();
    if(event.target.id === "employeePhoto" && event.target.files[0]) fileToDataUrl(event.target.files[0]).then(src => $("employeePhotoPreview").src = src);
    if(event.target.id === "importBackupInput" && event.target.files[0]) importBackup(event.target.files[0]);
    if(event.target.id === "correctiveAction") $("correctiveOtherWrap").hidden = event.target.value !== "Outro";
    if(event.target.closest("#view-settings")) persistSettingsFromInputs();
  });
  document.addEventListener("input", event => {
    if(event.target.id === "occurrenceQuantity") $("occurrenceSeverity").value = quantitySeverity(event.target.value).label;
    if(event.target.closest("#view-settings")) persistSettingsFromInputs();
  });
  $("employeeForm").addEventListener("submit", saveEmployee);
  $("cancelEmployeeButton").addEventListener("click", clearEmployeeForm);
  $("newEmployeeButton").addEventListener("click", () => { clearEmployeeForm(); setView("employees"); });
  $("noteForm").addEventListener("submit", saveNote);
  $("cancelNoteButton").addEventListener("click", () => $("noteDialog").close());
  $("saveEvalButton").addEventListener("click", saveEvaluation);
  $("clearEvalButton").addEventListener("click", () => { if(confirm("Limpar avaliação atual?")){ currentEval = emptyEvaluation(); currentEval.employeeId = $("evalEmployee").value; $("evalPositive").value = $("evalGeneralNote").value = $("evalJustification").value = ""; renderChecklist(); } });
  $("previewImageButton").addEventListener("click", () => { const data = collectEvaluation(); drawShareArt(data); setView("reports"); });
  $("weeklyReportButton").addEventListener("click", () => renderSelectedReport("weekly"));
  $("fortnightReportButton").addEventListener("click", () => renderSelectedReport("fortnight"));
  $("monthlyReportButton").addEventListener("click", () => renderSelectedReport("monthly"));
  $("compareReportButton").addEventListener("click", () => renderSelectedReport("compare"));
  $("pdiReportButton").addEventListener("click", () => renderSelectedReport("pdi"));
  $("downloadImageButton").addEventListener("click", () => downloadArt(4));
  $("downloadPdfButton").addEventListener("click", () => window.print());
  $("whatsappButton").addEventListener("click", sendEvaluationWhatsApp);
  $("quickShareButton").addEventListener("click", () => { setView("reports"); renderSelectedReport(); });
  $("exportBackupButton").addEventListener("click", exportBackup);
  $("resetDataButton").addEventListener("click", () => { if(confirm("Apagar todos os dados locais?")){ localStorage.removeItem(STORAGE_KEY); state = structuredClone(defaults); currentEval = emptyEvaluation(); renderAll(); } });
  $("evalDate").addEventListener("change", () => currentEval.date = $("evalDate").value);
  $("evalMonth").addEventListener("change", () => currentEval.month = $("evalMonth").value);
}

function init(){
  $("evalDate").value = currentEval.date;
  $("evalMonth").value = currentEval.month;
  $("employeePhotoPreview").src = defaultPhoto;
  setupEvents();
  renderAll();
}

if(document.readyState === "loading") document.addEventListener("DOMContentLoaded", init, {once:true});
else init();

